// Limpeza simples de ESTOQUE por empresa (179, 037, 199)

const EMPRESAS_INTERESSADAS = new Set(["179", "037", "199"]);

// pega todos os items
const todos = items.map(i => i.json);

const hoje = new Date().toISOString().slice(0, 10);
const saida = [];

for (const p of todos) {
  const codigoProduto = String(p.codigoProduto || "").trim();
  if (!codigoProduto) continue;

  const saldos = Array.isArray(p.saldoEmpresas) ? p.saldoEmpresas : [];

  for (const s of saldos) {
    let codEmpresa = String(s.codigoEmpresa || "").trim();

    if (codEmpresa.length === 2) codEmpresa = "0" + codEmpresa;

    if (!EMPRESAS_INTERESSADAS.has(codEmpresa)) continue;

    const estoqueDisponivel = Number(s.saldoDisponivel) || 0;

    saida.push({
      codigoProduto,
      empresa: codEmpresa,
      estoqueDisponivel,
      dataColeta: hoje
    });
  }
}

// n8n: [{json}]
return saida.map(r => ({ json: r }));

// ==============================================
// LIMPEZA DE VENDAS (final - pronto)
// ==============================================

// Normaliza datas
function normalizaData(s) {
  if (!s) return null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const d = new Date(s);
  if (!isNaN(d.getTime())) return d.toISOString().slice(0, 10);
  return null;
}

// número seguro
function toNumber(v, def = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : def;
}

// código produto limpo
function normalizaCodigoProduto(codigo) {
  return String(codigo || "").trim();
}

// extrai todos os itens de vendas
const rows = [];

for (const wrapper of items) {
  const pag = wrapper.json;
  const pedidos = Array.isArray(pag?.content) ? pag.content : [];

  for (const pedido of pedidos) {
    const empresa = String(pedido?.codigoEmpresa || "").trim();
    if (!empresa) continue;

    const itens = Array.isArray(pedido?.itens) ? pedido.itens : [];

    for (const item of itens) {
      const codigoProduto = normalizaCodigoProduto(item?.codigoProduto);
      if (!codigoProduto) continue;

      const quantidade = toNumber(item?.quantidade, 0);
      if (quantidade <= 0) continue;

      const data = 
        normalizaData(item?.dataFaturamento) ||
        normalizaData(item?.dataEntrada);

      if (!data) continue;

      rows.push({
        codigoProduto,
        empresa,
        data,
        quantidade
      });
    }
  }
}

return rows.map(r => ({ json: r }));

